const Q_CHEMISTRY_1999=[{"id": "objective>Chemistry>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases will diffuse fastest when passed through a porous plug? <br/> [H = 1, C = 12, N = 14, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Propane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Graham's law of diffusion, the rate of diffusion of a gas is inversely proportional to the square root of its molar mass. Therefore, methane (CH4) with the lowest molar mass will diffuse fastest.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> From the equation above, the mass of magnesium required to react with 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.5M HCl is <br/> [Mg = 24]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.3g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2.4g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar conc. =no.of moles/Vol in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Vol=250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>= 0.25dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Molar conc=0.5M <br/> No of moles=molar conc * Vol in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> =0.5*0.25 <br/> =0.125mole of HCl <br/> 2moles of HCl →  １Mole of Mg <br/> 0.125 mole →(0.125*1)/2 <br/> =0.0625mole of Mg <br/> Reacting mass=no of moles * molar mass <br/> Mg=24 <br/> Mass=0.0625*24 <br/> =1.5g</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What  is the temperature of a given mass of a gas initially at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C and 9 atm, if the pressure is reduced to 3 atm at constant volume? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">91K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">182K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">273K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">819K</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P1V1/T1=P2V2/T2 <br/> Since volume is constant, the volume cancel out and we have P1/T1 = P2/T2  <br/> T1= 0 + 273=273 <br/> From P1/T1 = P2/T2 = 9/273 = 3/T2 <br/> T2 x 9 = 273 x 3 <br/> T2 = (273 x 3)/9 <br/> T2 = 91K</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">56.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas at S.T.P. weighed 0.11g. What is the vapour density of the gas? <br/> [Molar volume of a gas at S.T.P = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">44.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">56.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas at S.T.P weighed 0.11g <br/> Molar volume of the gas = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 22400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> molar mass = (22400 x 0.11)/56 <br/> molar mass = 2464/56 = 44 <br/> Vapour density = Molar mass/2 = 44/2 = 22</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gaseous metallic chloride MCl consists of 20.22% of M by mass. The formula of the chloride is? <br/> [M = 27, Cl = 35.5]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Percentage by mass of M = 20.22% <br/> Percentage by mass of Cl = ? <br/> 100 - 20.22 = 79.78% <br/> Mass given ration of M <br/> M = 20.22/27 = 0.75 <br/> Chlorine = 79.78/35.5 = 2.24 <br/> Divide by the smallest <br/> M = 0.75/0.75 = 1 <br/> Cl = 2.24/0.75 = 3 <br/> ∴ The formula = MCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will have its mass increased when heated in air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Helium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper pyrites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glass</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When magnesium is heated in air, it reacts with oxygen to form magnesium oxide, thereby increasing its mass. This is due to the fact that magnesium is a highly reactive metal that readily reacts with oxygen in the air when heated. The other options do not react with air when heated.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> each of 0.1M solutions of lead (II) trioxonitrate (V) and hydrochloric acid were mixed. Assuming that lead (II) chloride is completely insoluble, calculate the mass of lead (II) chloride that will be precipitated. <br/> [Pb = 207, Cl= 35.5, N = 14, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.78g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.56g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.34g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.12g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(3)</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)(aq) + 2HCl(aq) → PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(s) + 2HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>(aq) <br/> From the balanced equation, <br/> 1 mole of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> reacted with 2 moles of HCl to produce 1 mole of PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> using, molar concentration = no of moles/volume in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> therefore, no of moles = molar concentration x volume in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> where, molar concentration of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.1M <br/> volume of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> therefore, no of moles of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.1M x 0.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.02 mol <br/>  <br/> no of moles = molar concentration x volume in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> where, molar concentration of HCl = 0.1M <br/> volume of HCl in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> therefore, no of moles of HCl = 0.1M x 0.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.02 mol <br/>  <br/> but from the balanced equation of the reaction, 1mol of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> reacted with 2 moles of HCl to produce 1mol of PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, <br/> This means that only 0.01 mole out of the 0.02 mole of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gives 0.01 mole of PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/> The 0.01 mole of PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> produced can be converted to grams by multiplying it with the molarmass of PbCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(278) i.e 0.01 × 278 = 2.78g</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the mixture of the solids P and Q can be separated by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fractional distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fractional crystallization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fractional crystallization is used to separate two or more solid solutes which are present in the same solution in roughly equal amounts. the solubilities of different solutes in the given solvent must differ at different temperatures</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen obtained from the liquefaction of air has a higher density than that obtained from nitrogen containing compounds because the former contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rare gases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen obtained from the liquefaction of air has a higher density than that obtained from nitrogen containing compounds because the former contains rare gases. Rare gases are inert gases that do not react with other elements and are heavier than nitrogen, thus increasing the density of the nitrogen obtained.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>, 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, 3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>, 3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>, 4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. An element with this electronic configuration is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">non-metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transition element</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> group two element</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The given electronic configuration corresponds to a transition element. Transition elements are elements whose atoms have an incomplete d sub-shell, or which can give rise to cations with an incomplete d sub-shell. In this case, the 3d sub-shell is incomplete with 7 electrons, hence it is a transition element.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The method that can be used to convert hard water to soft water is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passage over activated charcoal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of an ion-exchange resin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aeration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use of an ion-exchange resin is a method that can be used to convert hard water to soft water. Ion-exchange resins are insoluble substances containing loosely held ions which are to be exchanged with other ions in a solution that is passed over them. This process is used to soften water by exchanging magnesium and calcium ions in the water with sodium ions.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that electronegativity increases across a period and decreases down a group in the periodic table, in which of the following compounds will the molecules be held together by the strongest hydrogen bond?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bonding is strongest in HF because fluorine is the most electronegative element. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The higher the electronegativity, the stronger the hydrogen bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to remove one electron from a 3S-orbital of gaseous sodium atom, about 496KJMol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> of energy is required. This energy is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electron affinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activation evergy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electronegativity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy required to remove one electron from an atom is referred to as ionization energy. In this case, the energy required to remove one electron from a 3S-orbital of gaseous sodium atom is the ionization energy.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following are water molecules in the most disorderly arrangement?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ice at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ice at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Water at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steam at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In steam at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C, water molecules are in the most disorderly arrangement. This is because steam is in the gaseous state, and in this state, the molecules have the highest kinetic energy and are moving freely and randomly, hence the disorderly arrangement.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">I</td><td style=\"border:1px solid black;text-align:center;\">II</td><td style=\"border:1px solid black;text-align:center;\">III</td><td style=\"border:1px solid black;text-align:center;\">IV</td><td style=\"border:1px solid black;text-align:center;\">V</td><td style=\"border:1px solid black;text-align:center;\">VI</td><td style=\"border:1px solid black;text-align:center;\">VII</td><td style=\"border:1px solid black;text-align:center;\">O</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">X</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Z</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">W</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Y</td><td style=\"border:1px solid black;text-align:center;\"></td></tr></table></div> <br/>  <br/> The element that is likely to participate in covalent rather than ionic bonding is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Element X is in Group IV of the periodic table. Elements in this group have 4 electrons in their outermost shell and tend to form covalent bonds by sharing these electrons with other atoms. Therefore, element X is likely to participate in covalent rather than ionic bonding.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the table to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">I</td><td style=\"border:1px solid black;text-align:center;\">II</td><td style=\"border:1px solid black;text-align:center;\">III</td><td style=\"border:1px solid black;text-align:center;\">IV</td><td style=\"border:1px solid black;text-align:center;\">V</td><td style=\"border:1px solid black;text-align:center;\">VI</td><td style=\"border:1px solid black;text-align:center;\">VII</td><td style=\"border:1px solid black;text-align:center;\">O</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">X</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Z</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">W</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Y</td><td style=\"border:1px solid black;text-align:center;\"></td></tr></table></div> <br/> The least reactive element is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Z is least reactive, or totally unreactive because it has a duplet or octet electronic configuration</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is observed when aqueous solutions of each of tetraoxosulphate (VI) acid, potassium trioxoiodate (V) and potassium iodide are mixed together?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A white precipitate is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A green precipitate is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mixture remains colourless</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mixture turns reddish brown</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When aqueous solutions of tetraoxosulphate (VI) acid, potassium trioxoiodate (V) and potassium iodide are mixed together, the iodide ion reduces the trioxoiodate (V) ion to iodine which is reddish brown in colour. Hence, the mixture turns reddish brown.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solution with the lowest pH value is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 ml of (m/10) HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 ml of (m/10) HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 ml of (m/5) HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 ml of (m/8) HCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">pH only depends on concentration, volume doesn't affect the pH. <br/> Concentration =M/10=0.1M <br/> pH=-log 0.1 =1 <br/>  <br/> Concentration =M/8=0.125M <br/> pH=-log 0.125 =0.9 <br/>  <br/> Concentration =M/5=0.2M <br/> pH=-log 0.2 =0.7(lowest)</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of increasing oxidation number of the transition metal ions for the compounds K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> and KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> < K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> < KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> <  KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>  <  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>   <  K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> < V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> < K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>, </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of the transition metal ions in the compounds V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>, K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> and KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> are +5, +6 and +7 respectively. Therefore, the correct order of increasing oxidation number is V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> < K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> < KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above the mass of crystals deposited when 1 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of NaCl is cooled from 80 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is <br/> [Na = 23, Cl = 35.5]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">117.00 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">58.50 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.70 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.85 g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">solubility=m×1000/M×V <br/> solubility=10-8=2mol/dm³ <br/> M=23+35.5=58.5g <br/> 1 dm³=1×1000cm³ <br/> m=2×58.5×1000/1000 <br/> m=117g</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility product of Cu(IO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 1.08 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>. Assuming that neither ions react appreciable with water to form H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>, what is the solubility of this salt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 2.7 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ksp=(x)(x). 1.08*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>=(2x)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>(x). 1.08*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>=4x^3. x^3=1.08*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>/4. x^3=0.27*10^-7 x^3=27*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span> x=cubic root of 27*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span> x=3*10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> </div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The set of pollutants that is most likely to be produced when petrol is accidentally spilled on plastic materials and ignited is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO, HCl and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and HCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When petrol is accidentally spilled on plastic materials and ignited, the combustion of the hydrocarbons in the petrol and the chlorinated hydrocarbons in the plastic materials produces carbon monoxide (CO), carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and hydrogen chloride (HCl). Therefore, the set of pollutants that is most likely to be produced is CO, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and HCl.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">0.25 mole of hydrogen chloride was dissolved in distilled water and the volume made up of 0.50 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. If 15.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of the solution requires 12.50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of aqueous sodium trioxocarbonate (IV) for neutralization, calculate the concentration of the alkaline solution</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 0.30 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.60 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C=n/V <br/> C=0.25/0.50=0.5mol/dm³ <br/> 2HCl+NaOH -------> 2NaCl+H2CO3 <br/> CaVa/CbVb=na/nb <br/> 0.5×15/Cb×12.50 =2/1 <br/> Cb=0.5×15×1/12.50×2 <br/> Cb=7.5/25 <br/> Cb=0.3mol/dm³</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> ⇌ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>. Increase in total pressure of the equilibrium reaction above will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">produce more of NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> in the mixture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convert all of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> to NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">have no effect on the concentrations of NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce more of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> in the mixture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, if a dynamic equilibrium is disturbed by changing the conditions, the position of equilibrium moves to counteract the change. In the equilibrium reaction N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> ⇌ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>, increasing the total pressure will shift the equilibrium to the side with fewer gas molecules to reduce the pressure. Therefore, it will produce more of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> in the mixture.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">RS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + HF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → RF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + HS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> <br/> ΔH = -65.7 kj mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. <br/> From the equation above, it can be deduced that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the heat content of the reactants is lower than that of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the heat content of the reactants is higher than that of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction is slow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large amount of heat is absorbed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ΔH value in a chemical reaction represents the change in enthalpy, or heat content, of the system. A negative ΔH value indicates that the reaction is exothermic, meaning that heat is released and the heat content of the products is lower than that of the reactants. Therefore, the heat content of the reactants is higher than that of the products.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">X + Y → Z. The rate equation for the chemical reaction above is −Δx/Δt = K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[Y]. <br/> The overall order of the reaction is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The overall order of a chemical reaction is the sum of the powers to which the concentration terms are raised in the rate equation. In the rate equation −Δx/Δt = K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[Y], the overall order of the reaction is 2 (from [X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) + 1 (from [Y]) = 3.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>. In the chemical reaction above, the substance that will increase the rate of production of sulphur (VI) oxide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manganese (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">finely divided iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vanadium (V) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nickel</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the chemical reaction 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>, the rate of production of sulphur (VI) oxide can be increased by adding a catalyst. A catalyst is a substance that increases the rate of a chemical reaction by providing an alternative reaction pathway with a lower activation energy. Vanadium (V) oxide is a known catalyst for this reaction.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is true of the electrochemical series?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of metals increase down the series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of non-metals decrease down the series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electronegativity of non-metals decrease down the series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of metals decreases down the series</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity of metals decreases down the series</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What quantity of electricity will liberate 0.125 mole of oxygen molecules during the electrolysis of dilute sodium chloride solution? <br/> [ F = 96 5000 C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> ]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">24 125 coulombs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48 250 coulombs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">72 375 coulombs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">96 500 coulombs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n=m/M <br/> m=n×M <br/> M=16×2=32 <br/> m=0.125×32=4g <br/> 96500×2 ------------ 16g <br/> 96500×2×4/16 ------- 4g <br/> 48250 Columbus. <br/> or <br/> 4 Faradays of electricity is required to liberate one mole of oxygen gas <br/> ∴ quantity of electricity required <br/> = 0.125 * 4 * 96500 = 48250 coulombs <br/>  <br/> 4OH- ------> 2H2O + O2 + 4e- <br/> From the equation above,  <br/>  <br/> 4 Faradays of electricity is required to liberate one mole of oxygen gas <br/> ∴ X Faraday of electricity required to liberate 0.125 mole of oxygen gas  <br/>  <br/> But 1 Faraday of electricity = 96500C <br/> Therefore; <br/> 4 × 96500 coulombs of electricity is required to liberate 1 mole of oxygen gas <br/> ∴ X coulombs of electricity required to liberate 0.125 mole of oxygen gas  <br/> X = 0.125 × 4 × 96500  <br/>    = 48250 coulombs</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The entropy and enthalpy of a system are a measure of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">degree of disorderlinesss and heat content respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat content and degree of disorderliness respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat content of a system only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of disorderliness only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is the measure of disorderliness in a system while enthalpy is the measure of heat content of a system.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a current I was passed through an electrolyte solution for 40 minutes, a mass X g of a univalent metal was deposited at the cathode. What mass of the metal will be deposited when a current 2I is passed through the solution for 10 minutes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X/4 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X/2 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2X g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4X g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From M = zit <br/> Where M = to the mass of the metal liberated <br/> z = Is the electrochemical equivalent <br/> ∴ X g = 1 * 1 * 40 * 60 <br/> X g = 2400 I <br/> Let a represent the new mass <br/> a = 1*2I * 10 * 60 <br/> a = 1200 I <br/> a/(X g) = 1200 I/2400 I <br/> a = X/2 g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen is used in oxy-hydrogen flames for melting metals because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolves a lot of heat when burnt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combines explosively with oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a very light gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a rocket fuel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen is used in oxy-hydrogen flames for melting metals because it evolves a lot of heat when burnt. This high heat of combustion makes it ideal for processes that require high temperatures, such as melting metals.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pair of compounds that can be used to generate a gas which has physiological effect on human beings is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxonitrate (V) and calcium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium dioxonitrate (III) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxonitrate (V) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium dioxonitrate (III) and potassium chloride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxonitrate (V) reacts with  ammonium chloride to form Ammonium trioxonitrate(v) and sodium chloride  <br/>  <br/> NaNO₃ + NH₄Cl → NH₄NO₃ + NaCl <br/>  <br/> Ammonium trioxonitrate(v) decomposes to produce N₂O which has a physiological effect on humans <br/>  <br/> NH₄NO₃ →  N₂O + 2H₂O <br/>  <br/> N₂O causes uncontrollable fits of laughter when inhaled</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that will form a white precipitate with acidified silver trioxonitrate (v) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> react with HCl,one of the product is AgCl which is insoluble in water,thereby given out a white precipitate</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, Y is a mixture of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide and sodium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> sodium chloride and ammonuim trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium dioxonitrate (lll) and ammouium chloride</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram above, Y is a mixture of calcium hydroxide and ammonium chloride</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine, bromine and iodine resemble one another in that they?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissolve in alkalis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">react violently with hydrogen without heating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are liquids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">displace one another from solutions of their salts</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine, bromine and iodine resemble one another in that they dissolve in alkalis</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The salt that reacts with dilute hydrochloric acid to produce a pungent smelling gas which decolourizes acidified purple potassium tetraoxomanganate (VII) solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (sodium sulfite) reacts with dilute hydrochloric acid to produce a pungent smelling gas (sulfur dioxide) which decolourizes acidified purple potassium tetraoxomanganate (VII) solution.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pair of metals in the reactivity series that are usually extracted by the electrolysis of their ores is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium and zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium and calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper and zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead and calcium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium and calcium are usually extracted by the electrolysis of their ores. This is because they are highly reactive metals and cannot be extracted by reduction with carbon, a common method for less reactive metals.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What properties of duralumin make it more useful than its constituent metals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is heavy with a high melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is malleable and has high density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is strong and light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is hard and ductile</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Duralumin is an alloy (a mixture of metals) primarily of aluminum (over 90%) combined with copper (about 4%), manganese (0.6%) and magnesium (0.5%). These elements contribute to the strength and lightness of duralumin, making it more useful than its constituent metals.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals is passive to concentrated trioxonitrate (V) acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zinc</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminum and Iron does not react with concentrated HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> due to the formation of a surface coating of oxide which is passive and stops any further action on the acid. <br/> As a result concentrated HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is usually transported in containers lined with aluminum or iron</div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal that can be extracted from cassiterite is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cassiterite is a tin oxide mineral, SnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. Tin is extracted from this ore.</div>", "topic": "METALS AND THEIR COMPOUNDS : TIN"}, {"id": "objective>Chemistry>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When excess ethanol is heated to 145<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C in the presence of concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, the product is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diethyl sulphate</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> diethyl ether</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acetone</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When excess ethanol is heated to 145 degrees Celsius in the presence of concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, the product is diethyl ether. This is a dehydration reaction where two molecules of ethanol combine to form ether with the elimination of a water molecule.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many grammes of bromine will saturate 5.2g of but-1-ene-3-yne? <br/> [C=12,H=1,Br=80]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">64.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">but -1-ene-3-yne = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. <br/> but -1-ene-3-yne will require 3 moles of Bromine (3Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) for complete saturation . <br/>  <br/> Equation of reaction... <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 3Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ==> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <br/>  <br/> where C= 12g, H = 1g Br = 80g <br/>  <br/> From the reaction above... <br/> 52g of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> saturates 6(80) g of Bromine <br/> 52g C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> ==> 480g Br <br/> therefore... <br/> 5.2g C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will saturate ==> (5.2 × 480)/52 <br/> ==> 48g of Bromine.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the two end alkyl groups ethyl ethanoate are interchange, the compound formed is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">methyl ethanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyl propanaote</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> methyl propanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propyl ethanoate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the two end alkyl groups of ethyl ethanoate are interchanged, the compound formed is methyl propanoate.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylprop-1-ene is an isomer of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">but-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pent-1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbut-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbut-1-ene</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylprop-1-ene is an isomer of but-2-ene. Isomers are compounds with the same molecular formula but different structural formulas.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a solvent for perfumes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH) is a common solvent for perfumes due to its ability to dissolve a wide range of organic compounds and its volatility which helps to spread the scent.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the compounds above would react to take up two molecules of bromine during bromination?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">l only</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> lll only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">l and ll only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ll and lll only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of diatomic molecule e.g bromine is needed to break the double bond into a single bond in alkenes <br/>  <br/> Two moles of diatomic molecule is needed to break the triple bond into a single bond in alkynes</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrocarbon that burns in air with a sooty flames is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benzene (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>) burns in air with a sooty flame. This is because it has a high carbon to hydrogen ratio which leads to incomplete combustion, producing soot (carbon particles).</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound that does not undergo a reaction with both hydrogen cyanide and hydroxylamine can be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoic acid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkenes do not undergo a reaction with both hydrogen cyanide and hydroxylamine. Hydrogen cyanide adds across the carbon-oxygen double bond in aldehydes and ketones to produce cyanohydrins. Hydroxylamine reacts with aldehydes and ketones to give oximes. Alkenes do not have a carbon-oxygen double bond, so they do not react with these reagents.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Polyvinyl chloride is used to produce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bread</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pencils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pipes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polyvinyl chloride (PVC) is a type of plastic that is used for a variety of purposes, including the production of pipes. It is not used in the production of bread, pencils, or ink.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}];
